-- Enrichment marathon batch: Maza ad blocking, Maze, McAfee, Medama Analytics, MediaCMS, MediaMTX, MediaWiki, Medusa

-- ── Maza ad blocking ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Maza is a free, open-source Bash script that blocks ads and trackers system-wide on macOS, Linux, BSD and WSL by rewriting the operating system's own DNS resolution, with no router or extra device required.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Maza Ad Blocking Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Maza is a free, open-source Bash-based DNS ad blocker for macOS, Linux, BSD and WSL. See how it works, key features, pricing and top alternatives like Pi-hole.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Maza (maza-ad-blocking) is a free, open-source, single-file Bash script created by developer Andros Fenollosa, known as tanrax on GitHub, that blocks ads and trackers at the DNS level using only the host operating system's own DNS resolution tools. Unlike Pi-hole, which typically runs as a separate service on dedicated hardware such as a Raspberry Pi acting as a network-wide DNS sink, Maza runs locally on the same machine it protects, requiring no additional device, container, browser extension, or app installation. It is compatible with macOS, Linux, BSD, and Windows Subsystem for Linux (WSL). Maza works by downloading a curated list of ad- and tracker-serving domains and writing them into the operating system's DNS or hosts configuration, effectively blocking those domains for every browser and application on the machine at once rather than a single browser. By default, Maza uses the Yoyo (Peter Lowe) block list, which contains roughly 3,700 domains, but users can switch to more extensive lists such as Steven Black's hosts list, which blocks over 135,000 domains, by editing a single line in the script. Users can also append their own custom domains to a local configuration file to extend blocking beyond the default lists, and the entire block list can be refreshed with one command. The tool has no graphical interface, dashboard, or account system, reflecting a minimalist, command-line-first design aimed at developers, sysadmins, and privacy-conscious power users comfortable working in a terminal. The project is released under the Apache License 2.0 and is hosted both on GitHub (tanrax/maza-ad-blocking) and on the maintainer's self-hosted Git instance at git.andros.dev, with a marketing and documentation page at maza-ad-blocking.andros.dev. As a purely open-source utility with no company behind it, Maza has no funding, no enterprise tier, and no commercially driven roadmap; it is maintained on a volunteer, community basis. Its closest comparisons are Pi-hole and AdGuard Home, both of which provide similar DNS-based ad blocking but run as persistent network services, often on dedicated hardware or in Docker containers, that protect every device on a home network and include a web dashboard for statistics and management. Maza's key differentiation is simplicity: it is a lightweight script rather than a standing server, so it only protects the single machine it is installed on, but it requires none of the setup, port-forwarding, or hardware investment that Pi-hole demands. It is best suited to individual developers and privacy-conscious users who want fast, no-frills, script-based ad blocking on one laptop or desktop rather than centralized, network-wide protection for an entire household.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ff61bcc5-91e7-4059-9a0b-4ca89539d8cb';

