-- ── Maze ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Maze is a continuous product discovery and user-testing platform that lets product, design, and research teams validate ideas, test prototypes, and gather user feedback at scale.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE($q$Around 185 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Maze Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Maze is a rapid user-testing and product research platform for validating ideas and prototypes. See its features, pricing plans, pros, cons and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Maze is a continuous product discovery and user-testing platform founded in 2018 by Jonathan Widawski and Thomas Mary and headquartered in San Francisco, California. It is built for product managers, UX researchers, and designers who need to validate ideas, test prototypes, and collect user feedback quickly without running full traditional research studies. The platform combines several research methods in one workspace: usability and prototype testing (including live imports from design tools such as Figma, Adobe XD, and Sketch), five-second tests, card sorting, tree testing, surveys, live website testing, and moderated interview studies. Maze also offers an AI moderator that can run and summarize conversational interviews, and AI-assisted analysis features that summarize open-ended responses and highlight patterns across studies, positioning the product as a way to compress weeks of manual research synthesis into hours. Teams can recruit participants from Maze's own testers panel or bring their own users, and results are compiled into shareable, stakeholder-friendly reports with metrics like task success rate, misclick rate, and time on task. Maze operates on a freemium model: a free plan supports basic testing with limited monthly response volume, while paid plans (commonly referenced as Starter and Organization tiers, plus a custom Enterprise tier) unlock higher participant limits, panel recruitment, interview studies, AI-powered analysis, and enterprise security and support features, with per-seat pricing that scales from roughly the ninety-dollar range per seat per month at the entry paid tier up into the low hundreds per seat at higher tiers, billed primarily on an annual basis. In 2025 the company raised a growth funding round (reported at roughly twenty-two million euros) from investors including Cherry Ventures, Tapestry VC, and Theory Ventures, extending a funding history that began with earlier venture rounds after its 2018 founding. Maze's core differentiation versus generic survey tools or design-file commenting is its focus on quantifiable usability metrics tied directly to prototypes and live products, combined with fast turnaround: studies can be built, distributed, and analyzed within the same platform rather than stitching together separate tools for recruiting, testing, and reporting. Its main competitors include UserTesting, Lookback, UsabilityHub, and, for some workflows, Optimal Workshop, with Maze generally positioned as faster and more design-tool-integrated than heavier enterprise research suites, while still offering panel access and reporting depth beyond lightweight survey tools. Typical customers span startups running lean product discovery cycles up through larger product organizations that need to run frequent, low-friction usability checks alongside more formal research programs.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f57787ac-8e11-4769-9b64-15fa4453a73c';

