-- ── Medama Analytics ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Medama Analytics is a free, open-source, self-hostable website analytics platform that tracks visitors without cookies or IP addresses using a tracker script under 1KB.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Medama Analytics Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Medama Analytics is a free, open-source, privacy-focused website analytics tool with a sub-1KB tracker and no cookies. See features, self-hosting and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Medama Analytics is an open-source, self-hostable website analytics platform maintained by the medama-io organization on GitHub, built for developers and privacy-conscious site owners who want to measure traffic without relying on cookies, IP address storage, or other personally identifying data. The project's tracker script is deliberately kept under 1KB in size to minimize its impact on page load performance, and it is designed to help sites comply with privacy regulations such as GDPR and PECR without needing a cookie consent banner. Architecturally, Medama's backend is written in Go and exposes an OpenAPI-documented REST API, using SQLite and DuckDB for data storage and processing, while the dashboard is a React and TypeScript single-page application that renders real-time charts and tables of visitor activity. The system is distributed as a single, dependency-free binary, and the project states it can run on virtual machines with as little as 256MB of memory for most small websites, making it comparatively cheap to self-host relative to heavier analytics stacks. Licensing is split: the core Go API and the dashboard are released under the Apache License 2.0, while the small tracker JavaScript snippet embedded on customer websites is released under the MIT License, a common pattern for open-source analytics tools that want the client-side script to be maximally permissive. Medama does not appear to offer an official managed hosting or SaaS tier at this time; it is positioned purely as a self-hosted, do-it-yourself analytics tool, with a live demo available at demo.medama.io and documentation at oss.medama.io. As a smaller project, it has a modest but active open-source community on GitHub. Medama sits in the same category as other privacy-first, self-hostable web analytics tools such as Umami, Plausible Analytics, Fathom Analytics, and Simple Analytics, all of which position themselves as lightweight, cookie-free alternatives to Google Analytics. Medama's particular differentiation is its emphasis on being extremely lightweight and simple to deploy as a single binary with minimal external dependencies, combined with a dual-database approach using SQLite for smaller deployments and DuckDB for analytical query performance, plus a fully documented OpenAPI surface that makes it straightforward to integrate analytics data into custom dashboards or internal tools. It is best suited to developers and small-to-medium website operators who want full data ownership and minimal infrastructure overhead rather than a hosted, subscription-based analytics service.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd820a867-fd9f-44d0-a672-841fea19edfc';

