-- ── MediaCMS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$MediaCMS is a free, open-source video and media content management system built with Django and React that lets organizations run their own self-hosted video portal.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$MediaCMS Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$MediaCMS is a free, open-source video and media CMS built on Django and React. Compare its features, self-hosting options, pricing and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$MediaCMS is an open-source video and media content management system that lets organizations build and run their own self-hosted video and media portal, comparable in purpose to a self-hosted YouTube or Vimeo. Work on the project began in mid-2018, led primarily by developers Markos Gogoulos, who built the Python and Django backend, and Yiannis (Giannis) Stergiou, who built the React and JavaScript frontend. In 2020, the digital rights and media organization EngageMedia became MediaCMS's Product Development Partner, supporting its ongoing development, particularly for use cases in independent and community media. The platform is released under the GNU Affero General Public License v3.0 (AGPLv3), a copyleft license that requires modifications made to hosted, publicly accessible deployments to also be made available as open source. Technically, MediaCMS is built on Django and React with a REST API, and it can be deployed either via Docker Compose or through an automation script that installs and configures all required services on a server. The platform supports video, audio, image, and PDF media types, with features including multiple publishing workflows (public, private, unlisted, and custom visibility), role-based access control connecting users to groups with view and edit permissions on their media, automatic transcription powered by a locally-run instance of OpenAI's Whisper speech recognition model, in-browser video editing tools for trimming, replacing, and creating segments from uploaded video, and a customized video.js-based player supporting multiple resolutions and playback speeds. Because MediaCMS is free and open source, there is no license fee for self-hosting; the maintaining team instead offers paid professional services including custom installations, development of additional functionality, migration from legacy platforms, integrations, training, and support, priced on a custom basis per engagement. Third-party managed hosting providers, such as Elestio, also offer MediaCMS as a hosted service with pricing starting from roughly $11 per month for basic instances, though this is not an official MediaCMS product. MediaCMS is aimed at organizations that need to run their own branded, privacy-controlled video and media platform rather than relying on YouTube, Vimeo, or other third-party hosts, including universities, media organizations, community and non-profit groups, and businesses with internal video libraries. Its main open-source alternatives include PeerTube, another self-hosted, federated video platform, as well as commercial enterprise video platforms like Kaltura and Brightcove, and general-purpose self-hosted media servers. MediaCMS differentiates itself with its modern Django and React stack, integrated in-browser video editing, and built-in automatic transcription, aiming to give self-hosted deployments feature parity closer to commercial video platforms than older open-source alternatives.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '1761a911-bf5b-44d8-a1a3-2fca40562b85';

