-- ── MediaMTX ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$MediaMTX is a free, open-source, zero-dependency media server and proxy that reads, publishes, records, and converts real-time video and audio streams across protocols like RTSP, RTMP, WebRTC, SRT, and HLS.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$MediaMTX Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$MediaMTX is a free, open-source media server supporting RTSP, RTMP, WebRTC, SRT and HLS. See its features, how it works, licensing and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$MediaMTX is a free, open-source, zero-dependency media server and proxy distributed as a single executable that can publish, read, proxy, record, and play back real-time video and audio streams. The project was originally created and published as rtsp-simple-server, reflecting its initial scope as a simple RTSP server, but as its protocol support and use cases expanded well beyond RTSP, it was renamed to MediaMTX to better reflect its role as a general-purpose media router or media broker rather than a protocol-specific tool. The maintainer describes MediaMTX's role as routing media streams from one source or protocol to another, and the software is maintained under the bluenviron GitHub organization. It is released under the MIT License, making it free to use, modify, and redistribute, including in commercial products. MediaMTX supports a broad set of streaming protocols, including Media-over-QUIC, SRT, WebRTC, RTSP, RTMP, Low-Latency HLS (LL-HLS), MPEG-TS, and RTP, and it can automatically convert a stream published in one protocol into any of the others it supports, letting a single camera or encoder feed be consumed by clients expecting different protocols. It integrates with common tools in the streaming ecosystem such as FFmpeg, OBS Studio, GStreamer, and standard web browsers for WebRTC and HLS playback. Beyond basic relaying, MediaMTX supports recording streams to disk in fMP4 or MPEG-TS formats, offers a Control API for programmatic management of the server, and exposes Prometheus-compatible metrics for monitoring stream health and server performance. Authentication can be configured internally, via HTTP callbacks, or via JWT tokens, giving operators flexibility in how they secure publishing and playback endpoints. Because it ships as a single, dependency-free binary that runs on Linux, Windows, and macOS, MediaMTX is commonly used to build video surveillance systems, IP camera relays, live streaming backends, and IoT and robotics video pipelines where lightweight, protocol-flexible media routing is needed without the overhead of a full media server stack like Wowza or a cloud-only service. As an actively maintained, community-driven open-source project rather than a commercial company, MediaMTX has no pricing tiers, support contracts, or company behind it in the traditional sense; users rely on the GitHub repository, documentation, and community for support. Its closest comparisons include other open-source streaming servers such as Wowza Streaming Engine (commercial), Nginx with the RTMP module, SRS (Simple Realtime Server), and Janus WebRTC Gateway, with MediaMTX differentiating itself through its unusually broad multi-protocol support in a single, zero-dependency binary.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c';

