-- ── MediaWiki ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$MediaWiki is the free, open-source wiki software originally built for Wikipedia and now maintained by the Wikimedia Foundation, powering Wikipedia and thousands of other wikis worldwide.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2002, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States (Wikimedia Foundation)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$and hundreds of other languages via localization$q$]::text[],
  seo_title = COALESCE($q$MediaWiki Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$MediaWiki is the free, open-source wiki software that powers Wikipedia. Explore its features, extensions, licensing, and top alternatives for building wikis.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$MediaWiki is free, open-source wiki software written in PHP that was originally developed to run Wikipedia and now powers most of the Wikimedia Foundation's projects, including Wikipedia, Wiktionary, Wikimedia Commons, Wikiquote, Wikivoyage, Meta-Wiki, and Wikidata, as well as thousands of independent third-party wikis across the internet. Wikipedia itself launched in January 2001 running on an earlier Perl-based engine called UseModWiki. In January 2002, Magnus Manske developed a new PHP-based script to replace it, and later that year Lee Daniel Crocker rewrote the software again, calling the new version 'Phase III'; this rewrite was deployed to the English Wikipedia in July 2002 and forms the direct ancestor of modern MediaWiki. The Wikimedia Foundation was announced on June 20, 2003 to formally support Wikipedia and its sister projects, and shortly afterward, in July 2003, contributor Daniel Mayer suggested naming the software 'MediaWiki' as a play on 'Wikimedia.' The name was phased in starting in August 2003, and the first officially versioned release, MediaWiki 1.1, shipped in December 2003. Since then, development has been coordinated primarily by the Wikimedia Foundation along with a large volunteer developer community, with the software released under the GNU General Public License version 2 or later (GPLv2+), a copyleft open-source license. Architecturally, MediaWiki is built in PHP with a MySQL or MariaDB-backed database by default, and it uses a lightweight markup language called wikitext for page authoring, alongside built-in revision history tracking, discussion pages, granular user permissions, and full-text search. Its functionality is heavily extended through a large ecosystem of official and community-built extensions and skins; notable examples include the Wikibase extension introduced in 2012, which added support for structured data and underpins Wikidata, the VisualEditor extension launched in 2013, which added a WYSIWYG editing interface as an alternative to raw wikitext editing, and CirrusSearch, which integrates Elasticsearch for advanced full-text search across large wikis. Because MediaWiki is free and open source with no licensing cost, organizations self-host it on their own infrastructure or use third-party MediaWiki hosting providers, and the Wikimedia Foundation itself, headquartered in San Francisco, California, operates it at massive scale to serve Wikipedia's global traffic. MediaWiki's target audience spans the Wikimedia projects themselves, corporate and internal knowledge bases, community and fan wikis, government and academic documentation sites, and any organization that needs a collaboratively editable, version-controlled knowledge repository. Its main alternatives include Confluence (commercial, Atlassian), DokuWiki, TikiWiki, Notion (as a more modern collaborative workspace), and BookStack, with MediaWiki differentiating itself primarily through its proven ability to scale to Wikipedia's traffic levels, its very mature extension ecosystem, and its status as free, community-governed software rather than a commercial SaaS product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '56575211-4e45-4694-ace2-cf86a40a1535';

UPDATE tools SET logo = 'https://www.google.com/s2/favicons?domain=' || regexp_replace(regexp_replace(website, '^https?://', ''), '/.*$', '') || '&sz=256' WHERE id = '56575211-4e45-4694-ace2-cf86a40a1535' AND logo IS NULL AND website IS NOT NULL;

DELETE FROM tool_features WHERE tool_id = '56575211-4e45-4694-ace2-cf86a40a1535';

DELETE FROM tool_pros WHERE tool_id = '56575211-4e45-4694-ace2-cf86a40a1535';

DELETE FROM tool_cons WHERE tool_id = '56575211-4e45-4694-ace2-cf86a40a1535';

DELETE FROM tool_faqs WHERE tool_id = '56575211-4e45-4694-ace2-cf86a40a1535';

