INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$DNS-level blocking$q$, $q$Blocks ad and tracking domains by rewriting the operating system's DNS resolution rather than relying on a browser extension.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$No extra hardware or router setup$q$, $q$Runs directly on the protected machine using its own OS tools, unlike Pi-hole which typically needs a separate device.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$Cross-platform support$q$, $q$Works on macOS, Linux, BSD, and Windows Subsystem for Linux (WSL).$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$System-wide protection$q$, $q$Blocks ads and trackers across every browser and application on the machine at once, not just one browser.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$Switchable block lists$q$, $q$Ships with the Yoyo (Peter Lowe) list by default and can be switched to Steven Black's larger 135k-domain list with a one-line change.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$Custom domain blocking$q$, $q$Users can add their own domains to a local configuration file to extend or personalize blocking.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$One-command updates$q$, $q$The full block list can be refreshed with a single terminal command.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$Zero dependencies$q$, $q$Distributed as a single Bash script with no external runtime, package manager, or installer required.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$Completely free and open source under the Apache License 2.0$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$No router, dedicated hardware, or network reconfiguration required$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$Extremely lightweight, a single Bash script rather than a running service$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$Blocks ads and trackers for every app on the machine, not just the browser$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$Easy to customize with personal domain blocklists$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$No graphical interface or dashboard, command-line only$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$Only protects the single machine it is installed on, not a whole network$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$Very small, niche project with a much smaller community than Pi-hole or AdGuard Home$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$No official mobile app support$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$Documentation and support are community-driven with no commercial backing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$What is Maza ad blocking?$q$, $q$Maza is a free, open-source Bash script that blocks ads and trackers by rewriting DNS resolution on the local operating system, similar in concept to Pi-hole but without needing a separate device.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$How is Maza different from Pi-hole?$q$, $q$Pi-hole runs as a network-wide DNS server, typically on separate hardware, protecting every device on a network. Maza instead runs locally on a single machine using that machine's own DNS tools, so it only protects the device it is installed on.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$Does Maza work in every browser?$q$, $q$Yes, because it blocks domains at the DNS level rather than inside a single browser, Maza affects all browsers and any other software on the machine that makes network requests.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$Is Maza free?$q$, $q$Yes, Maza is free and open source under the Apache License 2.0, with no paid plans or subscriptions.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$What operating systems does Maza support?$q$, $q$Maza is documented to work on macOS, Linux, BSD, and Windows Subsystem for Linux (WSL).$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$Can I add my own blocklists to Maza?$q$, $q$Yes, users can add custom domains to a local configuration file, and can also swap the default Yoyo list for larger third-party lists such as Steven Black's hosts file.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$Single-machine ad blocking for developers$q$, $q$Provides DNS-level ad and tracker blocking on a personal laptop or workstation without needing a dedicated Pi-hole server.$q$, $q$Individual developers and technical users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$Lightweight privacy tool for terminal users$q$, $q$Offers a no-GUI, script-based way to reduce ad and tracker exposure for users who prefer managing tools from the command line.$q$, $q$Privacy-conscious command-line users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$Low-effort alternative to Pi-hole$q$, $q$Useful for people who want basic DNS-based ad blocking without setting up and maintaining separate server hardware.$q$, $q$Home users without spare hardware for a dedicated ad-blocking server$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full DNS-level ad and tracker blocking","Default Yoyo block list (about 3,700 domains)","Optional switch to Steven Black's list (135k+ domains)","Custom domain blocklist support","Works on macOS, Linux, BSD and WSL"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Maza is a lightweight, open-source ad blocker distributed as a single Bash script rather than a full application or service. It is designed to be a simpler alternative to Pi-hole for people who only need to protect one machine and do not want to set up a dedicated server, router change, or piece of hardware.$q$, $q$The tool works by rewriting DNS resolution at the operating system level, so once installed it blocks known ad and tracking domains for every browser and application on the machine, not just a single browser extension's scope.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Maza ships with the Yoyo (Peter Lowe) block list by default, covering roughly 3,700 known ad-serving domains, and can be reconfigured in one line to use larger community lists such as Steven Black's hosts file, which covers well over 135,000 domains.$q$, $q$Because it relies entirely on native OS tooling, Maza has no background daemon, browser extension, or account to manage. Custom domains can be added to a local config file, and the whole block list is refreshed with a single command, which keeps the tool easy to audit and modify for technically inclined users.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Maza is completely free and open source under the Apache License 2.0. There is no paid tier, subscription, or account system of any kind.$q$, $q$Because there is no company monetizing the project, users get the full functionality of the script at no cost, but should also expect community-level support rather than commercial SLAs or dedicated customer service.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ff61bcc5-91e7-4059-9a0b-4ca89539d8cb', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Prototype and usability testing$q$, $q$Import prototypes directly from Figma, Adobe XD, or Sketch and test them with real users, capturing task success and completion metrics automatically.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$AI moderator$q$, $q$Runs and summarizes conversational interview studies at scale, reducing the manual effort of moderating and transcribing user interviews.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Surveys and five-second tests$q$, $q$Supports quick quantitative and qualitative feedback methods for testing messaging, first impressions, and concepts.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Card sorting and tree testing$q$, $q$Helps teams validate information architecture and navigation structures before building them.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Live website testing$q$, $q$Tests usability directly on published, live websites and products, not just design prototypes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Participant recruitment panel$q$, $q$Access to Maze's own tester panel for recruiting study participants, in addition to bringing your own users.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Automated reporting$q$, $q$Generates shareable reports with usability metrics like task success rate, misclick rate, and time on task.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$AI-assisted analysis$q$, $q$Summarizes open-ended responses and surfaces patterns across studies to speed up research synthesis.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Combines multiple research methods, prototype testing, surveys, interviews, and live testing, in one platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Strong integrations with design tools like Figma, Adobe XD, and Sketch$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$AI moderator and AI analysis features speed up research synthesis$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Built-in participant recruitment panel removes the need for a separate recruiting tool$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Reports are designed to be shareable and easy for non-researchers to understand$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Free plan has limited monthly response and testing volume$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Per-seat pricing on paid tiers can get expensive for larger teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Some advanced features like interview studies and panel recruitment are gated to higher-priced tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Less suited to deep, long-form ethnographic or in-person research compared to specialized research tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$AI-generated summaries still require human review for nuanced findings$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$What is Maze used for?$q$, $q$Maze is used by product, design, and research teams to test prototypes, run surveys, conduct interviews, and gather usability feedback from real users before and after launch.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Is Maze free to use?$q$, $q$Maze offers a free plan with limited monthly usage, alongside paid Starter, Organization, and custom Enterprise plans that unlock higher limits and additional features.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Does Maze integrate with Figma?$q$, $q$Yes, Maze integrates directly with Figma as well as Adobe XD and Sketch, allowing teams to import and test prototypes without leaving their design workflow.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Where is Maze headquartered?$q$, $q$Maze is headquartered in San Francisco, California, and was founded in 2018.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$How is Maze different from UserTesting?$q$, $q$Maze focuses on fast, self-serve, prototype-centric usability testing with strong design-tool integrations and AI-assisted analysis, while UserTesting is a broader, more enterprise-oriented research platform with a larger participant network and more formal research workflows.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Can Maze recruit test participants for me?$q$, $q$Yes, Maze provides access to its own panel of testers for recruiting study participants, in addition to allowing teams to invite their own users.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Rapid prototype validation$q$, $q$Product and design teams test Figma or Adobe XD prototypes with real users before development begins, catching usability issues early.$q$, $q$Product designers and UX researchers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Continuous product discovery$q$, $q$Product managers run frequent, lightweight studies alongside the product roadmap to validate features and reduce build risk.$q$, $q$Product managers and product teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Post-launch usability checks$q$, $q$Teams test live websites and products to catch usability regressions and gather ongoing customer feedback.$q$, $q$Growth and UX teams at SaaS companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Limited monthly responses and tests","Prototype and usability testing","Basic reporting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Starter$q$, $q$Approximately $99 per seat per month$q$, $q$Annual$q$, NULL, $q$["Up to a few seats","Increased tester limits per month","Core testing methods and reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Organization$q$, $q$Approximately $200+ per seat per month$q$, $q$Annual$q$, NULL, $q$["Higher usage limits","Interview studies and panel recruitment","AI-assisted analysis"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Enterprise-grade security and administration","Dedicated support","Custom usage limits and contract terms"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Maze is a product research and user-testing platform that helps teams get fast, quantifiable feedback on prototypes, live products, and early ideas. It is built around the idea of continuous product discovery, letting product managers, designers, and researchers run smaller, more frequent studies instead of relying only on occasional, large-scale research projects.$q$, $q$Founded in 2018 and based in San Francisco, Maze has grown into a platform used by product teams to combine usability testing, surveys, interviews, and analytics in a single workspace, with direct integrations into design tools such as Figma, Adobe XD, and Sketch.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Maze supports a range of research methods including prototype and usability testing, five-second tests, card sorting, tree testing, surveys, and live website testing, alongside moderated interview studies enhanced by an AI moderator that can conduct and summarize conversations at scale.$q$, $q$The platform includes participant recruitment through its own testers panel, automated reporting with usability metrics such as task success rate and misclick rate, and AI-assisted analysis that summarizes open-ended feedback and surfaces patterns, reducing the manual work typically required to synthesize research findings.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f57787ac-8e11-4769-9b64-15fa4453a73c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Maze offers a free plan with limited monthly usage suitable for small teams testing the platform, alongside paid Starter and Organization tiers priced per seat and billed primarily on an annual basis, plus a custom-priced Enterprise tier for larger organizations.$q$, $q$Paid tiers unlock higher response and participant limits, access to Maze's recruiting panel, interview studies, AI-powered analysis features, and enterprise-grade security, administration, and support, with per-seat costs increasing significantly between the entry paid tier and the top tiers.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Real-time antivirus and malware protection$q$, $q$Scans for and removes viruses, ransomware, spyware, and other malware in real time across supported devices.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Built-in VPN$q$, $q$Encrypts internet traffic, particularly useful on public Wi-Fi, included with most paid McAfee plans.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Identity theft protection and monitoring$q$, $q$Monitors for exposure of personal information and provides restoration support if identity theft occurs on higher-tier plans.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Password manager$q$, $q$Stores and autofills credentials securely across devices as part of bundled security suites.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Web protection (WebAdvisor)$q$, $q$Browser extension that flags risky websites, links, and downloads before users interact with them.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Parental controls$q$, $q$Lets families monitor and manage children's device usage and online activity.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Multi-device coverage$q$, $q$Single subscriptions can cover multiple devices across Windows, macOS, Android, and iOS.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Business and enterprise security$q$, $q$Separate enterprise product line offers endpoint protection and threat intelligence for organizations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Long operating history and strong brand recognition in cybersecurity$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Bundles antivirus, VPN, identity protection, and password management in one subscription$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Broad multi-device and cross-platform support$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Frequently pre-installed or bundled by PC manufacturers and ISPs, easing initial adoption$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Offers identity theft monitoring and restoration support on higher tiers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Renewal pricing after the introductory first year can be significantly higher$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Historically criticized for aggressive upsells and background resource usage on some devices$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Some advanced features like identity protection are gated behind higher-priced tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Frequent ownership and rebranding changes over its history can create confusion about current offerings$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Free version offers only very limited protection compared to paid competitors$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Who founded McAfee?$q$, $q$McAfee was founded in 1987 by John McAfee, who released one of the earliest commercial antivirus programs.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Is McAfee still owned by John McAfee?$q$, $q$No, John McAfee resigned from the company in 1994. The company has since changed hands multiple times, including a period as part of Intel, and is now privately owned following a 2022 acquisition led by Advent International and Permira.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$What is included in McAfee Total Protection?$q$, $q$McAfee Total Protection bundles antivirus and malware scanning with a VPN, password manager, and identity theft protection features, with the exact feature set varying by plan tier.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Does McAfee offer a free version?$q$, $q$McAfee offers limited free tools and trial scans, but full real-time protection, VPN, and identity features require a paid subscription.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$How does McAfee pricing work?$q$, $q$McAfee typically sells introductory first-year pricing that renews at a higher standard annual rate, with cost increasing by plan tier and number of covered devices.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$What are the main alternatives to McAfee?$q$, $q$Common alternatives include Norton (Gen Digital), Bitdefender, Kaspersky, Avast, and Malwarebytes.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$All-in-one home device protection$q$, $q$Individuals and families use McAfee to cover multiple devices with antivirus, VPN, and web protection in a single subscription.$q$, $q$Consumers and families$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Identity theft monitoring$q$, $q$Users concerned about data breaches and identity fraud use McAfee's monitoring and restoration support to catch and respond to exposure.$q$, $q$Privacy and identity-conscious consumers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Business endpoint security$q$, $q$Organizations use McAfee's separate enterprise security products for endpoint protection and threat intelligence.$q$, $q$IT and security teams at businesses$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Basic$q$, $q$From about $29.99 for the first year (introductory)$q$, $q$Annual$q$, NULL, $q$["Antivirus and malware protection","Web protection","Limited device coverage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Plus$q$, $q$From about $39.99 per year$q$, $q$Annual$q$, NULL, $q$["Coverage for up to five devices","Includes VPN","Antivirus and web protection"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Premium$q$, $q$Approximately $50 to $55 per year (regional pricing varies)$q$, $q$Annual$q$, NULL, $q$["Coverage for up to ten devices","VPN and password manager","Identity monitoring features"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$Advanced$q$, $q$Varies by region and promotion$q$, $q$Annual$q$, NULL, $q$["Highest device coverage","Full identity theft protection and restoration support","VPN, password manager, and web protection"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$McAfee is a cybersecurity company founded in 1987 by John McAfee, credited with releasing one of the earliest commercial antivirus programs. Over nearly four decades the company has changed ownership and structure multiple times, including a period as part of Intel and a stint as a public company, before being taken private again in 2022.$q$, $q$Today McAfee is primarily known for its consumer security suites, sold under the McAfee+ and Total Protection brands, which bundle antivirus protection with a VPN, identity monitoring, and a password manager into a single subscription.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$McAfee's core offering is real-time antivirus and malware scanning, complemented by a firewall, web protection tools that flag risky links and sites (WebAdvisor), and a built-in VPN for encrypting internet traffic on public networks.$q$, $q$Higher-tier plans add identity theft monitoring and restoration support, credit monitoring in some markets, a password manager, parental controls, and coverage for multiple devices across Windows, macOS, Android, and iOS.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('620140b0-3b84-4d9d-8196-7bb9344c797c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$McAfee sells tiered consumer subscriptions, commonly Basic, Plus, Premium, and Advanced, that scale by the number of covered devices and the depth of identity protection and VPN features included.$q$, $q$Plans are typically sold with a discounted introductory price for the first year, after which they renew at a higher standard annual rate, a pricing pattern common across the consumer antivirus industry.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Cookie-free tracking$q$, $q$Tracks visitor activity without setting cookies or storing IP addresses, simplifying privacy compliance.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Sub-1KB tracker script$q$, $q$The client-side tracking snippet is kept under 1KB to minimize page load impact.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Self-hostable single binary$q$, $q$Ships as a dependency-free binary that can run on minimal infrastructure, reportedly as low as 256MB of memory.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Go backend with SQLite and DuckDB$q$, $q$Uses SQLite for storage and DuckDB for analytical processing, balancing simplicity with query performance.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$OpenAPI-documented REST API$q$, $q$Exposes a fully documented API for integrating analytics data into custom dashboards or internal tools.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Real-time dashboard$q$, $q$React and TypeScript dashboard displays live visitor charts and tables.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Privacy regulation alignment$q$, $q$Designed to help sites comply with GDPR, PECR, and similar privacy laws without a cookie consent banner.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Completely free and open source$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$No cookies or IP address storage, simplifying privacy compliance$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Very lightweight tracker script with minimal performance impact$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Low infrastructure requirements make self-hosting inexpensive$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Fully documented OpenAPI REST API for custom integrations$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$No official managed hosting or SaaS plan, requires self-hosting expertise$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Smaller community and ecosystem compared to Umami or Plausible$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Documentation and long-term support depend on an open-source community rather than a company$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Feature set is more limited than commercial, full-featured analytics platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$No confirmed enterprise support or SLA options$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$What is Medama Analytics?$q$, $q$Medama Analytics is an open-source, self-hostable website analytics platform that tracks visitors without cookies or IP addresses, using a lightweight tracker under 1KB in size.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Is Medama Analytics free?$q$, $q$Yes, Medama is free and open source, with the core API and dashboard licensed under Apache License 2.0 and the tracker script under the MIT License.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Does Medama Analytics require cookie consent banners?$q$, $q$Medama is designed to avoid using cookies and does not store IP addresses, which is intended to help sites comply with privacy laws like GDPR and PECR without needing a cookie banner.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Can I self-host Medama Analytics?$q$, $q$Yes, Medama is built specifically to be self-hosted as a single, dependency-free binary, and the project states it can run on machines with as little as 256MB of memory.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$What technology does Medama Analytics use?$q$, $q$The backend is written in Go and uses SQLite and DuckDB for storage and analytical processing, while the dashboard is built with React and TypeScript.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$How does Medama Analytics compare to Umami or Plausible?$q$, $q$Like Umami and Plausible, Medama is a privacy-first, cookie-free analytics alternative to Google Analytics. Medama differentiates itself with an especially lightweight tracker, low memory requirements, and a dual SQLite and DuckDB storage approach.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Privacy-compliant website analytics$q$, $q$Site owners use Medama to measure traffic without collecting cookies or IP addresses, easing GDPR and PECR compliance.$q$, $q$Privacy-conscious website operators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Self-hosted analytics for small infrastructure$q$, $q$Developers deploy Medama on low-resource VMs or containers to avoid the cost and complexity of larger analytics platforms.$q$, $q$Developers and indie site owners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Custom analytics integrations$q$, $q$Teams use Medama's OpenAPI-documented REST API to pull visitor data into internal dashboards or tools.$q$, $q$Engineering teams building custom reporting$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Cookie-free, IP-free tracking","Sub-1KB tracker script","Self-hosted single binary deployment","OpenAPI REST API access","Real-time dashboard"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Medama Analytics is an open-source website analytics tool designed to be self-hosted, giving site owners full control and ownership of their visitor data. It targets developers and organizations that want to measure site traffic without using cookies or storing IP addresses, helping simplify privacy compliance.$q$, $q$The project is maintained on GitHub under the medama-io organization and is distributed as a single, dependency-free binary alongside a lightweight client-side tracker script, making it straightforward to deploy on a small VM or container.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Medama's tracker script is kept under 1KB and avoids collecting cookies, IP addresses, or other identifying data, aiming for compliance with privacy regulations like GDPR and PECR without a cookie consent banner. The backend, written in Go, uses SQLite and DuckDB for storage and analytical queries, while an OpenAPI-documented REST API makes it easy to pull analytics data into custom tools.$q$, $q$The dashboard is a React and TypeScript application offering real-time charts and tables for exploring visitor behavior. The project reports that it can run on machines with as little as 256MB of memory, making it inexpensive to self-host for most small to medium websites.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Medama Analytics is free and open source. The core API and dashboard are licensed under Apache License 2.0, while the tracker script is licensed under the MIT License.$q$, $q$There is no known official managed hosting or paid SaaS tier; users are expected to self-host the software on their own infrastructure, similar to other open-source analytics tools in its category.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('d820a867-fd9f-44d0-a672-841fea19edfc', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Multi-format media support$q$, $q$Supports video, audio, image, and PDF content within a single platform.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Flexible publishing workflows$q$, $q$Content can be published as public, private, unlisted, or under custom visibility rules.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Role-based access control$q$, $q$Connects users to groups with defined view and edit permissions on media items.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Automatic transcription$q$, $q$Generates transcripts using a locally run Whisper speech recognition integration.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$In-browser video editing$q$, $q$Lets users trim, replace, or create new segments from uploaded video directly in the browser.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Customized video player$q$, $q$Uses a video.js-based player supporting multiple resolutions and playback speeds.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$REST API$q$, $q$Exposes a REST API for integrations and building custom clients or workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Self-hosted deployment options$q$, $q$Can be deployed via Docker Compose or an automation script that provisions all required services on a server.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Free and open source under the AGPLv3 license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Full control and ownership of hosted video and media content$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Modern tech stack built on Django and React with a REST API$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Built-in automatic transcription and in-browser video editing$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Flexible publishing and access control workflows suited to organizations of varying sizes$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Requires self-hosting expertise and server infrastructure to run and maintain$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$AGPLv3 license requires derivative hosted services to also be open sourced$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$No official managed SaaS offering directly from the MediaCMS project$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Smaller community and ecosystem compared to platforms like PeerTube$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Professional support and custom development require a paid services engagement$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$What is MediaCMS used for?$q$, $q$MediaCMS is used to build and run a self-hosted video and media portal, similar in purpose to a private YouTube or Vimeo, for organizations that want to control their own media hosting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Is MediaCMS free?$q$, $q$Yes, MediaCMS is free and open source under the GNU Affero General Public License v3.0. There is no license fee to self-host it.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$What technology stack does MediaCMS use?$q$, $q$MediaCMS is built with Django (Python) on the backend and React (JavaScript) on the frontend, exposing a REST API.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Does MediaCMS support automatic transcription?$q$, $q$Yes, MediaCMS integrates with a locally run instance of the Whisper speech recognition model to generate automatic transcripts for uploaded video and audio.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$How do I deploy MediaCMS?$q$, $q$MediaCMS can be deployed using Docker Compose, or via an automation script that installs and configures all required services on a server.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$What is the difference between MediaCMS and PeerTube?$q$, $q$Both are open-source, self-hosted video platforms. MediaCMS is built on Django and React with features like in-browser editing and Whisper-based transcription, while PeerTube is built around federation using the ActivityPub protocol to share content across servers.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Self-hosted organizational video portal$q$, $q$Organizations deploy MediaCMS to host internal or public video libraries without relying on third-party platforms like YouTube.$q$, $q$Universities, media organizations, and enterprises$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Community and non-profit media hosting$q$, $q$Community media groups use MediaCMS, supported by partners like EngageMedia, to publish and manage independent media content.$q$, $q$Non-profits and community media organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Internal training and knowledge video libraries$q$, $q$Businesses use MediaCMS to organize and control access to internal training videos and media assets.$q$, $q$Enterprise IT and L&D teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under AGPLv3","Video, audio, image and PDF support","Role-based access control","Automatic transcription and in-browser editing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$Professional Services$q$, $q$Custom$q$, $q$Per engagement$q$, NULL, $q$["Custom installation and configuration","Custom feature development","Migration from legacy platforms","Training and support"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MediaCMS is an open-source content management system purpose-built for video and other media types, letting organizations run their own self-hosted video and media portal. Development began in mid-2018, led by Markos Gogoulos on the backend and Yiannis Stergiou on the frontend, with EngageMedia joining as a Product Development Partner in 2020.$q$, $q$The platform is released under the GNU Affero General Public License v3.0, and is built using Django for the backend and React for the frontend, with a REST API supporting integrations and custom clients.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$MediaCMS supports video, audio, image, and PDF uploads, multiple publishing workflows for controlling visibility, and role-based access control that connects users to groups with defined view and edit permissions on media items.$q$, $q$The platform includes automatic transcription through a locally run Whisper integration, in-browser video editing to trim, replace, or create new segments from uploaded footage, and a customized video.js player with multiple resolution and playback speed options.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$MediaCMS itself is free and open source, with no license fee to self-host on your own infrastructure. Organizations that need help deploying or customizing it can purchase professional services directly from the MediaCMS team, including custom installations, feature development, migrations, integrations, training, and support.$q$, $q$Third-party managed hosting providers also offer MediaCMS as a hosted service, with entry-level pricing around $11 per month reported by at least one provider, though this is separate from the official open-source project.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1761a911-bf5b-44d8-a1a3-2fca40562b85', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Multi-protocol streaming support$q$, $q$Supports Media-over-QUIC, SRT, WebRTC, RTSP, RTMP, LL-HLS, MPEG-TS, and RTP in a single server.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Automatic protocol conversion$q$, $q$Converts streams published in one protocol into any other supported protocol automatically.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Stream recording$q$, $q$Records incoming streams to disk in fMP4 or MPEG-TS format.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Control API$q$, $q$Provides an API for programmatically managing streams and server configuration.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Prometheus metrics$q$, $q$Exposes server and stream metrics in a format compatible with Prometheus monitoring.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Flexible authentication$q$, $q$Supports internal, HTTP-based, and JWT authentication for securing publish and read endpoints.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Zero-dependency single binary$q$, $q$Distributed as a single executable with no external dependencies, running on Linux, Windows, and macOS.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Broad tool compatibility$q$, $q$Works with FFmpeg, OBS Studio, GStreamer, and standard web browsers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Completely free and open source under the permissive MIT License$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Supports an unusually wide range of streaming protocols in one server$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Zero-dependency single binary, simple to deploy on Linux, Windows, or macOS$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Automatic protocol conversion reduces the need for separate transcoding tools$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Actively maintained with an API and Prometheus metrics for production use$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$No commercial support contracts or SLAs available$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Requires familiarity with streaming protocols and server configuration$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$No built-in graphical management dashboard out of the box$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Community-driven support only, via GitHub issues and documentation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Scaling to very high concurrent stream counts requires manual infrastructure planning$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$What is MediaMTX used for?$q$, $q$MediaMTX is used as a media server and proxy to publish, read, record, and convert real-time video and audio streams across protocols like RTSP, RTMP, WebRTC, SRT, and HLS.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Is MediaMTX free?$q$, $q$Yes, MediaMTX is free and open source under the MIT License, with no paid tiers or licensing fees.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$What was MediaMTX previously called?$q$, $q$MediaMTX was originally released as rtsp-simple-server before being renamed once its protocol support expanded beyond RTSP.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$What protocols does MediaMTX support?$q$, $q$MediaMTX supports Media-over-QUIC, SRT, WebRTC, RTSP, RTMP, LL-HLS, MPEG-TS, and RTP.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Can MediaMTX record streams?$q$, $q$Yes, MediaMTX can record incoming streams to disk in fMP4 or MPEG-TS formats.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Does MediaMTX work with FFmpeg and OBS Studio?$q$, $q$Yes, MediaMTX is designed to integrate with common streaming tools including FFmpeg, OBS Studio, and GStreamer, as well as standard web browsers.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$IP camera and video surveillance relay$q$, $q$Organizations use MediaMTX to relay and record streams from IP cameras across different protocols to viewing clients.$q$, $q$Security and surveillance system integrators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Live streaming backend$q$, $q$Developers use MediaMTX as a lightweight backend to ingest and distribute live streams for web or app-based viewing.$q$, $q$Developers building live streaming products$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$IoT and robotics video pipelines$q$, $q$Teams use MediaMTX to route low-latency video feeds between devices, robots, and monitoring dashboards.$q$, $q$IoT and robotics engineers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Support for RTSP, RTMP, WebRTC, SRT, LL-HLS, MPEG-TS and RTP","Automatic protocol conversion","Stream recording in fMP4 or MPEG-TS","Control API and Prometheus metrics"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MediaMTX is an open-source media server and proxy that acts as a router for real-time video and audio streams, letting streams published in one protocol be read back in another. It began life as rtsp-simple-server, a lightweight RTSP-focused server, and was renamed to MediaMTX once its protocol support and use cases grew well beyond RTSP.$q$, $q$The project is maintained on GitHub under the bluenviron organization and released under the MIT License, making it free to use and modify, including in commercial deployments.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$MediaMTX supports a wide range of streaming protocols including Media-over-QUIC, SRT, WebRTC, RTSP, RTMP, LL-HLS, MPEG-TS, and RTP, and can automatically convert a stream from one protocol to another so a single source can serve clients with different requirements.$q$, $q$The server can record streams in fMP4 or MPEG-TS formats, exposes a Control API for programmatic management, and provides Prometheus-compatible metrics for monitoring, along with configurable internal, HTTP, or JWT-based authentication.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$MediaMTX is completely free and open source under the MIT License, with no paid tiers, licensing fees, or commercial entity behind it.$q$, $q$Because it ships as a single, dependency-free binary, operating costs are limited to the infrastructure running it, making it an inexpensive option compared to commercial media server products.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ddba0123-4cc5-4ad5-bf20-fbd6b10fd50c', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Wikitext markup and editing$q$, $q$Uses a lightweight markup language for authoring pages, with optional WYSIWYG editing via the VisualEditor extension.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Full revision history$q$, $q$Tracks every edit to every page, allowing changes to be reviewed, compared, and reverted.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Granular user permissions$q$, $q$Supports detailed user rights and roles for controlling who can view, edit, or administer content.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Discussion pages$q$, $q$Provides dedicated talk pages for collaborative discussion about article content and edits.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Structured data via Wikibase$q$, $q$The Wikibase extension adds structured, queryable data support, as used by Wikidata.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Advanced search via CirrusSearch$q$, $q$Integrates Elasticsearch for fast, advanced full-text search across large wikis.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Extensible via extensions and skins$q$, $q$A large ecosystem of extensions and skins allows deep customization of functionality and appearance.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Proven scalability$q$, $q$Powers Wikipedia and its sister projects, demonstrating the software's ability to handle very large-scale traffic and content volumes.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Proven at massive scale by powering Wikipedia and its sister projects$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Extremely mature and extensive extension and skin ecosystem$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Strong built-in collaboration features like revision history and discussion pages$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Backed by the Wikimedia Foundation and a large, active developer community$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Can be complex to install, configure, and maintain compared to simpler wiki tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Default visual design feels dated without applying custom skins$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Wikitext markup has a learning curve for non-technical users, despite VisualEditor$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Self-hosting requires ongoing server maintenance and security updates$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$No official managed hosting from the MediaWiki project itself$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$What is MediaWiki used for?$q$, $q$MediaWiki is used to build collaboratively editable wikis, most notably powering Wikipedia and its sister projects, as well as thousands of independent corporate, community, and personal wikis.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Is MediaWiki free?$q$, $q$Yes, MediaWiki is free and open source, licensed under the GNU General Public License version 2 or later, with no cost to download, install, or modify.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Who maintains MediaWiki?$q$, $q$MediaWiki is maintained primarily by the Wikimedia Foundation along with a large community of volunteer developers.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$What is the difference between MediaWiki and Wikipedia?$q$, $q$MediaWiki is the underlying software; Wikipedia is one of many websites (and the most famous one) that runs on that software.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Can I add features to MediaWiki?$q$, $q$Yes, MediaWiki supports a large ecosystem of extensions and skins that add functionality such as structured data (Wikibase), WYSIWYG editing (VisualEditor), and advanced search (CirrusSearch).$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$What are alternatives to MediaWiki?$q$, $q$Common alternatives include Confluence, DokuWiki, TikiWiki, BookStack, and more modern collaborative workspace tools like Notion, depending on the use case.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Public knowledge encyclopedias$q$, $q$MediaWiki powers Wikipedia and its sister projects, serving as the reference implementation for large-scale public wikis.$q$, $q$Nonprofit and public knowledge projects$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Internal corporate knowledge bases$q$, $q$Organizations self-host MediaWiki to document internal processes, policies, and technical knowledge collaboratively.$q$, $q$Enterprise IT and knowledge management teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Community and fan wikis$q$, $q$Communities use MediaWiki to build collaboratively edited reference sites around shared interests or topics.$q$, $q$Online communities and hobbyist groups$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$Self-Hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code under GPLv2+","Wikitext editing and revision history","Extension and skin ecosystem","Granular user permissions"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$MediaWiki is the free, open-source wiki software that powers Wikipedia and most of the Wikimedia Foundation's sister projects. It grew out of earlier wiki engines used in Wikipedia's first years, was rewritten in PHP in 2002, and took on the MediaWiki name in 2003 as the Wikimedia Foundation was established to support it.$q$, $q$Since its first official release, MediaWiki 1.1, in December 2003, it has been continuously developed by the Wikimedia Foundation together with a large open-source community, and is now used by thousands of wikis beyond the Wikimedia projects themselves.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$MediaWiki is built around a lightweight wikitext markup language for content authoring, with full revision history, discussion pages, granular user permissions, and built-in full-text search. Its functionality is significantly extended through a large ecosystem of official and community extensions and skins.$q$, $q$Notable extensions include Wikibase, introduced in 2012 to support structured data and power Wikidata, VisualEditor, launched in 2013 to provide a WYSIWYG editing experience, and CirrusSearch, which integrates Elasticsearch for advanced search across large-scale wikis.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$MediaWiki is free and open source under the GNU General Public License version 2 or later, with no licensing fees to install, run, or modify it.$q$, $q$Organizations can self-host MediaWiki on their own infrastructure at no software cost, or use third-party MediaWiki hosting providers that charge for managed hosting, though these are separate commercial services rather than official MediaWiki pricing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('56575211-4e45-4694-ace2-cf86a40a1535', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Modular commerce framework$q$, $q$Provides composable modules for product, cart, order, pricing, promotion, inventory, and fulfillment logic that developers can extend.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Headless, API-first architecture$q$, $q$Decouples the commerce backend from the frontend, allowing any storefront, app, or AI agent to consume the same commerce API.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$TypeScript and Node.js foundation$q$, $q$Built on a modern, widely-used JavaScript stack familiar to most web development teams.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$B2B and marketplace support$q$, $q$Includes primitives for complex B2B commerce, multi-vendor marketplaces, and distributor platforms.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Open-source core with MIT license$q$, $q$The full platform is free to self-host with no license fees or per-transaction charges.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Medusa Cloud managed hosting$q$, $q$Offers an official managed hosting option with tiered plans for teams that do not want to operate their own infrastructure.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Extensible plugin and integration ecosystem$q$, $q$Supports plugins and integrations for payments, shipping, search, and other commerce services.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Point-of-sale and service commerce support$q$, $q$Modular architecture extends beyond typical online storefronts to POS and service-based business models.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Core platform is completely free and open source with no license or transaction fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Modern TypeScript and Node.js stack familiar to most development teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Highly modular architecture suited to deep customization$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Supports B2B, marketplace, and POS use cases beyond simple DTC stores$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Official Medusa Cloud offers a managed hosting path when teams want to avoid self-ops$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Requires development resources; not a drag-and-drop store builder like Shopify$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Self-hosting demands infrastructure and DevOps expertise to run in production$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Smaller ecosystem of themes and pre-built extensions compared to mature platforms like Shopify$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Medusa Cloud pricing can add up with usage-based add-ons at scale$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Best suited to technical teams rather than non-technical merchants$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$What is Medusa (MedusaJS)?$q$, $q$Medusa is an open-source, headless commerce platform built on TypeScript and Node.js that gives developers modular building blocks for creating custom e-commerce, B2B, and marketplace applications.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Is Medusa free?$q$, $q$Yes, the core Medusa platform is free and open source under the MIT License, with no license fees or per-transaction charges when self-hosted.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Who founded Medusa?$q$, $q$Medusa was founded in 2021 in Copenhagen, Denmark, by Sebastian Rindom, Oliver Juhl, and Nicklas Gellner.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$What is Medusa Cloud?$q$, $q$Medusa Cloud is the official managed hosting service for Medusa, with published plans starting at $29 per month for the Develop tier, scaling up to a custom-priced Enterprise tier.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Is Medusa a good Shopify alternative?$q$, $q$Medusa is a strong alternative for technical teams that need deep customization or headless architecture, whereas Shopify is generally easier for non-technical merchants who want an out-of-the-box store.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$What can you build with Medusa?$q$, $q$Medusa can be used to build custom storefronts, B2B commerce portals, multi-vendor marketplaces, point-of-sale systems, and other commerce applications on top of its modular framework.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Custom headless storefronts$q$, $q$Development agencies and brands use Medusa to build fully custom storefronts decoupled from the commerce backend.$q$, $q$Developers and digital agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$B2B and marketplace platforms$q$, $q$Companies use Medusa's modular commerce primitives to build complex B2B ordering systems or multi-vendor marketplaces.$q$, $q$B2B commerce and marketplace businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$AI and agent-driven commerce$q$, $q$Teams building AI-driven shopping assistants or automated purchasing flows use Medusa's API-first architecture to power commerce logic.$q$, $q$Teams building AI commerce agents and automated workflows$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full MIT-licensed source code","Modular commerce framework","No license or transaction fees","Self-managed infrastructure"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Medusa Cloud Develop$q$, $q$From $29 per month$q$, $q$Monthly$q$, NULL, $q$["Managed hosting for development environments","Core commerce modules","Usage-based infrastructure billing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Medusa Cloud Launch$q$, $q$From $99 per month$q$, $q$Monthly$q$, NULL, $q$["Managed production hosting","Increased usage limits","Standard support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Medusa Cloud Scale$q$, $q$From $299 per month$q$, $q$Monthly$q$, NULL, $q$["Higher-scale managed hosting","Increased compute, storage, and data transfer limits","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$Medusa Cloud Enterprise$q$, $q$Custom$q$, $q$Annual$q$, NULL, $q$["Custom infrastructure and usage limits","Dedicated support and SLAs","Enterprise contract terms"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Medusa, widely known as MedusaJS, is an open-source headless commerce platform built for developers who want to build custom e-commerce, B2B, or marketplace applications without starting from scratch. Founded in 2021 in Copenhagen, Denmark, by Sebastian Rindom, Oliver Juhl, and Nicklas Gellner, the company raised an $8 million seed round in 2022 led by Dawn Capital.$q$, $q$The core platform is built on TypeScript and Node.js and released under the MIT License, making it free to self-host with no licensing fees, transaction fees, or gross-merchandise-value-based charges, distinguishing it from many commercial e-commerce platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Medusa provides a modular commerce framework made up of composable building blocks, including product, cart, order, pricing, promotion, inventory, and fulfillment modules, that developers can combine and extend to support advanced B2B, direct-to-consumer, marketplace, or point-of-sale use cases.$q$, $q$Because it is API-first and headless, Medusa can power any frontend, custom storefronts, mobile apps, or even AI-driven commerce agents, without being tied to a specific presentation layer, giving development teams full control over the customer experience.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Medusa's core platform is free and open source under the MIT License, so teams can self-host it on their own infrastructure at no licensing cost.$q$, $q$For teams that prefer managed hosting, Medusa Cloud offers published plans starting with Develop from $29 per month, Launch from $99 per month, and Scale from $299 per month, plus a custom-priced Enterprise tier, with usage-based add-ons for compute, storage, data transfer, and additional seats.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8c235fd0-f6aa-40a1-a259-80552567229d', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
